scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    scwin.clntNo = scwin.params["clntNo"];
    scwin.clntNm = scwin.params["clntNm"];

    // getCodeList
    const codeOptions = [
        { grpCd : "ZZ945", compID : "con_lc_sealKind, lc_sealKind" },
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.f_createHeader();
    lc_useYn.setSelectedIndex(-1);
};

